import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"艾尔登法环大卢恩系列","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/艾尔登法环大卢恩系列.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/艾尔登法环大卢恩系列.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/艾尔登法环大卢恩系列.md"};function o(_,r,d,l,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"艾尔登法环大卢恩系列",tabindex:"-1"},[t("艾尔登法环大卢恩系列 "),p("a",{class:"header-anchor",href:"#艾尔登法环大卢恩系列","aria-label":'Permalink to "艾尔登法环大卢恩系列"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="艾尔登法环大卢恩系列-1" tabindex="-1">艾尔登法环大卢恩系列 <a class="header-anchor" href="#艾尔登法环大卢恩系列-1" aria-label="Permalink to &quot;艾尔登法环大卢恩系列&quot;">​</a></h1><p>葛瑞克的大卢恩（伪）<br> 本质：特异本质<br> 价格：D+1000<br> 分类：戒指<br> 描述：</p><p>【「艾尔登之王」葛孚雷与其后代子孙——<br> 黄金一族是最先出现的半神。】</p><p>……并非位在艾尔登法环中心位置的重心法环</p><p>效果：</p><p>【接肢】</p><p>「软弱的男人利用恐怖的接肢，渴求着力量」</p><p>佩戴者将因为大卢恩上残留的些许接肢的力量，能够通过尸体的肢体获得力量。当你在一场同级战斗中获胜，你就可以摘下对方的一只手臂，接在自己身上，这视作在身体上任意选择的位置生长出一只手臂。（如果对方没有一般意义上的手臂，那么会改为直接生长出来）<br> 每影片最多以此法生长一条手臂，由此法带来的额外手臂将会在摘下戒指后消失。</p><p>【敬请见证！】</p><p>「众士兵啊——终有一天，我等将反家。<br> 一同返回黄金树脚的故乡。」</p><p>以一个移动动作激活大卢恩以降下恩惠。<br> 在恩惠中，肢体会不合常理地生长，仿佛杂草一般纠缠目标，这视为佩戴者的肉搏触及增加1米，当你的肉搏攻击命中时，可以附带一次拖拽，对方以反射豁免对抗本次攻击的出目，被拖拽差值*1M。</p><p>拉塔恩的大卢恩（伪）<br> 本质：特异本质<br> 价格：C+1000<br> 分类：戒指<br> 描述：</p><p>【拉塔恩是蕾娜菈与拉达冈的其中一位子嗣。<br> 在拉达冈成为玛莉卡女王的王夫之后，<br> 那群孩子成为外戚，也成为半神。】</p><p>效果：</p><p>【红狮子火焰】</p><p>「此大卢恩猛烈燃烧──<br> 为的是对抗猩红腐败的侵蚀。」</p><p>为了还原原物，这件仿制品表面刻上了形似熊熊烈火的符纹，璀璨的火光将映照于佩戴者的精神与肉体之中，佩戴者获得灵感视觉，同时攻击获得【法破】。</p><p>【重力魔法】</p><p>「红狮子将军能够操作重力──<br> 在拉塔恩的年轻时期，<br> 他前往瑟利亚学习重力魔法，<br> 为的是和那匹瘦马一起出生入死。」</p><p>「我正是英雄之子，也是战王的狮子。」</p><p>每场景一次，能以一个自由动作激活大卢恩的力量降下恩惠，在接下来的一场景中，来自红狮子将军的些许重力力量将使佩戴者获得飞行能力，机动性普通，同时英雄之子的信念也将令佩戴者屹立不倒，一往无前，即使生命值满严重也不会因此昏迷。</p><p>蒙葛特的大卢恩（伪）<br> 本质：特异本质<br> 价格：D+1000<br> 分类：戒指<br> 描述：</p><p>【…………<br> 这代表两件事情——<br> 一是「恶兆王」为黄金一族的成员，<br> 二是这位王确实是罗德尔之王。】</p><p>这不是……位在主干之上的重心法环。</p><p>效果：</p><p>【罗德尔之王】</p><p>「蒙葛特厌恶，封印诅咒之血……」</p><p>残留有恶兆王点滴意志的器物，依旧能使人意志坚定，<br> 此大卢恩能使佩戴者无视亢奋异常点数带来的减值及严重状态。</p><p>【黄金一族】</p><p>「即使生为与赐福无缘的恶兆之子，<br> 蒙葛特仍愿意成为黄金树的守卫──<br> 不是因为被爱，想要回馈，<br> 而是他单纯希望去爱。」</p><p>每场景一次，佩戴者可以用一个自由动作激活大卢恩降下恩惠，获得3点临时生命，持续一场景。</p><p>拉卡德的大卢恩（伪）<br> 本质：特异本质<br> 价格：D+500<br> 分类：戒指<br> 描述：</p><p>【拉卡德是蕾娜菈与拉达冈的其中一位子嗣。<br> 在拉达冈成为玛莉卡女王的王夫之后，<br> 那群孩子成为外戚，也成为半神。】</p><p>效果：</p><p>【亵渎】</p><p>「我很明了，亵渎之路有多么险峻──<br> 害怕犯下罪孽，哪能走这条路？」</p><p>此大卢恩中蕴含已然血液同化的王的族人们的点滴力量，融为一体的冤魂化作熔岩，铺就亵渎之路，在你使用白刃武器时，以你的触及范围视作D级影响心灵来源的困难地形。</p><p>【吞噬】</p><p>「然而拉卡德却让亵渎之蛇一口吞噬──<br> 包含自己本身，以及伟大的大卢恩。」</p><p>每影片一次，当你参与击杀一名目标时，你可以使用一个自由动作激活大卢恩降下恩惠，吞噬其尸体。若如此做，则佩戴者于影片结束时提高6点体积。并且由于来自不死大蛇的神话本质，佩戴此大卢恩者无需休息。</p><p>特殊的，由【吞噬】成长的体积不提供血量上的增长，如同虚拟体积一般处理。</p><p>蒙格的大卢恩（伪）<br> 本质：特异本质<br> 价格：C+1500<br> 分类：戒指<br> 描述：</p><p>【蒙格与蒙葛特是孪生兄弟，<br> 他们的大卢恩也很雷同。】</p><p>效果：</p><p>【诅咒之血】</p><p>「然而蒙格的大卢恩却染上诅咒之血，<br> 他蛰伏地底，深爱着与生俱来的玷污特质。」</p><p>此大卢恩中蕴含原物中部分诅咒之血的力量，因此佩戴者的攻击会附带1点不可豁免的创伤来源的流血点数。</p><p>【鲜血君王】</p><p>「蒙格视米凯拉为神，<br> 并且想当上神的伴侣，也就是王。」</p><p>每场景一次，可以以一个标准动作激活大卢恩降下恩惠，在接下来的一场景中，鲜血将激发君王仆从们的斗志，并治愈他们的伤痛。当以你为中心15米的圆形范围内有敌方或我方身上带有流血异常点数时，此范围内的我方目标的加骰提升一级，获得一点异常点数恢复（医疗点24）。</p><p>无缘诞生者的大卢恩（伪）<br> 本质：特异本质<br> 价格：D+500<br> 分类：消耗品<br> 描述：</p><p>【“满月女王”蕾娜菈抱着的琥珀卵。<br> 无缘诞生的半神拥有的大卢恩。】</p><p>效果：</p><p>【不完整的轮回】</p><p>「蕾娜菈的那群重新诞生的孩子，<br> 全部都相当脆弱，而且短命──<br> 原因就出在那不完整。」</p><p>虽然只是仿制品，但是依旧携带能够令人重新诞生的力量。但也正因为是仿制品，此大卢恩无法利用泪滴幼体作为材料，只能通过消耗自身来进行重新诞生的过程。持有者可以在主神空间中激活此大卢恩中的力量，选择自身拥有的X项内在强化放弃，所有内在强化提供的效果和属性全部失去，返还这些强化总价格的7成。激活之后，此大卢恩会因为力量耗尽而碎裂消散。</p><p>特殊的，由于重新诞生对躯体带来的负担，一位轮回者每经过三场影片最多可以洗点一次（无论是通过此法或者是洗点水），并且若某资源是可升级资源，则必须从最高级开始洗，有购买前置条件的资源同理。<br> 该资源同洗点水共用影片购买的限制（即你使用该资源洗点的同时，洗点水也会进入三场影片的时间限制）</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',59)])])}const m=b(s,[["render",o]]);export{f as __pageData,m as default};
